        .nav-dot .tooltip { visibility: hidden; opacity: 0; position: absolute; right: 180%; top: 50%; transform: translateY(-50%); background: var(--color-background-start); color: var(--color-text); padding: 0.5rem 1rem; border-radius: 6px; white-space: nowrap; transition: visibility 0s 0.3s, opacity 0.3s ease; pointer-events: none; }
        .nav-dot:hover .tooltip, .nav-dot:focus-visible .tooltip { visibility: visible; opacity: 1; transition-delay: 0.1s; }

        /* Points of Interest */
        .poi-container { position: absolute; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; z-index: 2; }
        .poi { position: absolute; width: 24px; height: 24px; padding: 0; border-radius: 50%; background: var(--color-highlight); border: none; cursor: pointer; pointer-events: all; transform: translate(-50%, -50%); display: flex; justify-content: center; align-items: center; transition: transform 0.3s ease; }
        .poi::before { content: ''; width: 100%; height: 100%; background: var(--color-highlight); border-radius: 50%; animation: poi-pulse 2.5s infinite cubic-bezier(0.42, 0, 0.58, 1); }
        .poi:hover, .poi:focus-visible { transform: translate(-50%, -50%) scale(1.2); }
        .poi:focus-visible { outline: none; }
        @keyframes poi-pulse { 0% { transform: scale(0.8); opacity: 0.5; } 70% { transform: scale(2.5); opacity: 0; } 100% { transform: scale(0.8); opacity: 0; } }
        .poi .tooltip { visibility: hidden; opacity: 0; position: absolute; bottom: 160%; left: 50%; transform: translateX(-50%); background: var(--color-background-start); color: var(--color-text); padding: 0.5rem 1rem; border-radius: 6px; white-space: nowrap; transition: visibility 0s 0.3s, opacity 0.3s ease; pointer-events: none; }
        .poi:hover .tooltip, .poi:focus-visible .tooltip { visibility: visible; opacity: 1; transition-delay: 0.1s; }

        /* Modal */
        #modal-container { position: fixed; inset: 0; background: rgba(0,0,5,0.7); z-index: 200; display: flex; justify-content: center; align-items: center; backdrop-filter: blur(8px); -webkit-backdrop-filter: blur(8px); opacity: 0; pointer-events: none; transition: opacity var(--transition-speed-fast) ease; }
        #modal-container:not(.hidden) { opacity: 1; pointer-events: all; }
        .modal-content { background: var(--color-background-start); border: 1px solid var(--color-highlight); padding: 2.5rem; border-radius: var(--border-radius); max-width: 90vw; width: 650px; position: relative; transform: scale(0.95) translateY(10px); transition: transform var(--transition-speed-fast) cubic-bezier(0.34, 1.56, 0.64, 1); box-shadow: 0 10px 40px rgba(0,0,0,0.5); }
        #modal-container:not(.hidden) .modal-content { transform: scale(1) translateY(0); }
        .modal-content h3 { color: var(--color-highlight); margin-bottom: 1rem; font-size: 1.8rem; }
        .modal-content p { font-size: 1.1rem; color: var(--color-text-muted); }
        .modal-close { position: absolute; top: 1rem; right: 1rem; background: none; border: none; color: var(--color-text-muted); font-size: 2rem; cursor: pointer; width: 44px; height: 44px; display: flex; justify-content: center; align-items: center; line-height: 1; transition: color 0.3s ease, transform 0.3s ease; }
        .modal-close:hover, .modal-close:focus-visible { color: var(--color-text); transform: rotate(90deg); }
        .modal-close:focus-visible { outline-offset: 0; }

        @media (max-width: 768px) {
            #scale-navigator { right: 1rem; gap: 1rem; }
            .nav-dot { width: 10px; height: 10px; }
            .nav-dot .tooltip { display: none; }
            #ui-container { bottom: 1rem; }
            .level-content { padding: 1.5rem; }
        }

        @media (prefers-reduced-motion: reduce) {
            *, *::before, *::after {
                animation-duration: 1ms !important;
                animation-iteration-count: 1 !important;
                transition-duration: 1ms !important;
                scroll-behavior: auto !important;
            }
        }
    </style>
</head>
<body>

