    </main>

    <nav id="scale-navigator" aria-label="Cosmic Scale Navigator"></nav>

    <div id="ui-container">
        <div id="scroll-prompt">
            <p class="sr-only">Scroll to explore</p>
            <div class="scroll-prompt-icon" aria-hidden="true"></div>
        </div>
        <button id="reset-button">Restart Journey</button>
    </div>

    <div id="modal-container" class="hidden" role="dialog" aria-modal="true" aria-labelledby="modal-title" aria-describedby="modal-info">
        <div class="modal-content">
            <button class="modal-close" aria-label="Close modal">&times;</button>
            <h3 id="modal-title"></h3>
            <p id="modal-info"></p>
        </div>
    </div>

    <div id="live-region" class="sr-only" aria-live="polite" aria-atomic="true"></div>

    <script>
        class CosmicJourney {
            constructor() {
                this.cacheDOMElements();
                this.initState();
                this.initStarfield();
                this.initUI();
                this.bindEventListeners();
            }

            cacheDOMElements() {
                this.dom = {
                    loadingOverlay: document.getElementById('loading-overlay'),
                    startButton: document.querySelector('.start-button'),
                    universe: document.getElementById('universe'),
                    zoomLevels: Array.from(document.querySelectorAll('.zoom-level')),
                    uiContainer: document.getElementById('ui-container'),
                    scrollPrompt: document.getElementById('scroll-prompt'),
                    resetButton: document.getElementById('reset-button'),
                    liveRegion: document.getElementById('live-region'),
                    scaleNavigator: document.getElementById('scale-navigator'),
                    modalContainer: document.getElementById('modal-container'),
                    modalTitle: document.getElementById('modal-title'),
                    modalInfo: document.getElementById('modal-info'),
                    modalClose: document.querySelector('.modal-close'),
                    starfieldCanvas: document.getElementById('starfield'),
                };
                this.starfieldCtx = this.dom.starfieldCanvas.getContext('2d');
            }

            initState() {
                const styles = getComputedStyle(document.documentElement);
                this.constants = {
                    ZOOM_FACTOR: parseFloat(styles.getPropertyValue('--zoom-factor')) || 50,
                    TRANSITION_SPEED: parseFloat(styles.getPropertyValue('--transition-speed')) * 1000 || 1600,
                    NUM_LEVELS: this.dom.zoomLevels.length,
                    STAR_COUNT: 500,
                };
                this.state = {
                    currentLevel: 0,
                    isAnimating: false,
                    touchStartY: 0,
                    audioInitialized: false,
                    modalOpen: false,
                    lastFocusedElement: null,
                };
                this.audio = { context: null, masterGain: null, sounds: [] };
                this.stars = [];
            }

            initUI() {
                this.dom.zoomLevels.forEach((level, index) => {
                    const scale = Math.pow(this.constants.ZOOM_FACTOR, -index);
                    level.style.transform = `scale(${scale})`;
                    const levelTitleElement = level.querySelector('h1, h2');
                    const levelTitle = levelTitleElement ? levelTitleElement.textContent : `Level ${index}`;
                    level.setAttribute('aria-labelledby', levelTitleElement.id);

                    const dot = document.createElement('button');
                    dot.className = 'nav-dot';
                    dot.setAttribute('aria-label', `Jump to ${levelTitle}`);
                    dot.addEventListener('click', () => this.changeLevel(index));
                    const tooltip = document.createElement('span');
                    tooltip.className = 'tooltip';
                    tooltip.textContent = levelTitle;
                    dot.appendChild(tooltip);
                    this.dom.scaleNavigator.appendChild(dot);
                });

                this.dom.zoomLevels[0].classList.add('active');
                this.dom.scaleNavigator.querySelector('.nav-dot').classList.add('active');
                this.updateLiveRegion();

                document.querySelectorAll('.poi').forEach(poi => {
                    const title = poi.dataset.title;
                    const tooltip = document.createElement('div');
                    tooltip.className = 'tooltip';
                    tooltip.textContent = title;
                    poi.appendChild(tooltip);
                    poi.setAttribute('aria-label', `Point of Interest: ${title}`);
                    poi.addEventListener('click', () => this.showModal(title, poi.dataset.info, poi));
                });
            }

            bindEventListeners() {
                this.dom.startButton.addEventListener('click', () => this.startExperience());
                window.addEventListener('wheel', this.debounce(this.handleWheel.bind(this), 50), { passive: false });
                window.addEventListener('keydown', this.handleKeyDown.bind(this));
                window.addEventListener('touchstart', e => { this.state.touchStartY = e.touches[0].clientY; }, { passive: true });
                window.addEventListener('touchmove', this.handleTouchMove.bind(this), { passive: true });
                this.dom.resetButton.addEventListener('click', () => this.resetZoom());
                this.dom.modalContainer.addEventListener('click', e => { if (e.target === this.dom.modalContainer) this.hideModal(); });
                this.dom.modalClose.addEventListener('click', () => this.hideModal());
                window.addEventListener('resize', this.debounce(() => {
                    this.resizeStarfield();
                    this.createStars();
                }, 250));
            }

            startExperience() {
                this.dom.loadingOverlay.classList.add('hidden');
                this.initAudio();
                this.updateAudioAmbience();
            }

            // --- Core Logic ---
            changeLevel(newLevel) {
                if (this.state.isAnimating || newLevel < 0 || newLevel >= this.constants.NUM_LEVELS || newLevel === this.state.currentLevel) return;
                this.state.currentLevel = newLevel;
                this.updateUniverse();
            }

            updateUniverse() {
                this.state.isAnimating = true;

                this.dom.zoomLevels.forEach((level, index) => {
                    level.classList.toggle('active', index === this.state.currentLevel);
                    level.setAttribute('aria-hidden', index !== this.state.currentLevel);
                });

                const totalScale = Math.pow(this.constants.ZOOM_FACTOR, this.state.currentLevel);
                const universeZ = this.state.currentLevel * -1000;
                this.dom.universe.style.transform = `translateZ(${universeZ}px) scale(${totalScale})`;

                this.dom.zoomLevels.forEach((level, index) => {
                    const levelScale = Math.pow(this.constants.ZOOM_FACTOR, -index);
                    level.style.transform = `scale(${levelScale})`;
                    level.style.opacity = (index >= this.state.currentLevel) ? '1' : '0';
                });

                this.updateUIState();
                this.updateAudioAmbience();
                this.preloadNextImage();

                setTimeout(() => { this.state.isAnimating = false; }, this.constants.TRANSITION_SPEED);
            }

            updateUIState() {
                this.dom.scrollPrompt.style.display = (this.state.currentLevel === 0) ? 'block' : 'none';
                this.dom.resetButton.classList.toggle('visible', this.state.currentLevel > 0);
                this.dom.uiContainer.classList.toggle('hidden', this.state.currentLevel === this.constants.NUM_LEVELS - 1);
                this.dom.scaleNavigator.querySelectorAll('.nav-dot').forEach((dot, index) => {
                    dot.classList.toggle('active', index === this.state.currentLevel);
                });
                this.updateLiveRegion();
            }

            updateLiveRegion() {
                const activeLevel = this.dom.zoomLevels[this.state.currentLevel];
                const levelTitle = document.getElementById(activeLevel.getAttribute('aria-labelledby')).textContent;
                this.dom.liveRegion.textContent = `Now viewing: ${levelTitle}`;
            }

            preloadNextImage() {
                const nextLevel = this.state.currentLevel + 1;
                if (nextLevel < this.constants.NUM_LEVELS) {
                    const nextImg = this.dom.zoomLevels[nextLevel].querySelector('.visual');
                    if (nextImg && nextImg.src) {
                        const img = new Image();
                        img.src = nextImg.src;
                    }
                }
            }

            // --- Event Handlers ---
            handleWheel(event) {
                if (this.state.isAnimating || this.state.modalOpen) return;
                event.preventDefault();
                if (event.deltaY > 0) this.zoomIn();
                else this.zoomOut();
            }

            handleKeyDown(event) {
                if (this.state.isAnimating && event.key !== 'Escape') return;
                if (this.state.modalOpen) {
                    if (event.key === 'Escape') this.hideModal();
                    if (event.key === 'Tab') this.trapFocus(event);
                    return;
                }
                const keyMap = {
                    'ArrowDown': () => this.zoomIn(),
                    'PageDown': () => this.zoomIn(),
                    'ArrowUp': () => this.zoomOut(),
                    'PageUp': () => this.zoomOut(),
                    'Home': () => this.resetZoom(),
                    'End': () => this.changeLevel(this.constants.NUM_LEVELS - 1),
                };
                if (keyMap[event.key]) {
                    event.preventDefault();
                    keyMap[event.key]();
                }
            }

            handleTouchMove(e) {
                if (this.state.isAnimating || this.state.modalOpen) return;
                const touchEndY = e.changedTouches[0].clientY;
                const deltaY = this.state.touchStartY - touchEndY;
                if (Math.abs(deltaY) > 50) {
                    if (deltaY > 0) this.zoomIn();
                    else this.zoomOut();
                    this.state.touchStartY = touchEndY;
                }
            }

            zoomIn() { this.changeLevel(this.state.currentLevel + 1); }
            zoomOut() { this.changeLevel(this.state.currentLevel - 1); }
            resetZoom() { this.changeLevel(0); }

            // --- Modal Logic ---
            showModal(title, info, triggerElement) {
                this.state.lastFocusedElement = triggerElement || document.activeElement;
                this.dom.modalTitle.textContent = title;
                this.dom.modalInfo.textContent = info;
                this.dom.modalContainer.classList.remove('hidden');
                this.state.modalOpen = true;
                this.dom.modalClose.focus();
            }

            hideModal() {
                this.dom.modalContainer.classList.add('hidden');
                this.state.modalOpen = false;
                if (this.state.lastFocusedElement) this.state.lastFocusedElement.focus();
            }

            trapFocus(event) {
                const focusableElements = 'button';
                const firstElement = this.dom.modalClose;
                const lastElement = this.dom.modalClose;

                if (event.shiftKey) { // shift + tab
                    if (document.activeElement === firstElement) {
                        lastElement.focus();
                        event.preventDefault();
                    }
                } else { // tab
                    if (document.activeElement === lastElement) {
                        firstElement.focus();
                        event.preventDefault();
                    }
                }
            }

            // --- Audio Engine ---
            initAudio() {
                if (this.state.audioInitialized) return;
                this.audio.context = new (window.AudioContext || window.webkitAudioContext)();
                if (this.audio.context.state === 'suspended') this.audio.context.resume();
                this.audio.masterGain = this.audio.context.createGain();
                this.audio.masterGain.gain.setValueAtTime(0.3, this.audio.context.currentTime);
                this.audio.masterGain.connect(this.audio.context.destination);

                const soundDefs = [
                    { type: 'sine', freq: 40, gain: 0.5 },
                    { type: 'sawtooth', freq: 60, gain: 0.2, filter: 400 },
                    { type: 'triangle', freq: 120, gain: 0.3 },
                    { type: 'pink-noise', gain: 0.15 },
                    { type: 'square', freq: 220, gain: 0.2 },
                    { type: 'sine', freq: 80, gain: 0.4 }
                ];

                soundDefs.forEach(def => {
                    const sound = {};
                    const gainNode = this.audio.context.createGain();
                    gainNode.gain.setValueAtTime(0, this.audio.context.currentTime);
                    gainNode.connect(this.audio.masterGain);
                    sound.gainNode = gainNode;

                    if (def.type.includes('noise')) {
                        const bufferSize = 2 * this.audio.context.sampleRate;
                        const buffer = this.audio.context.createBuffer(1, bufferSize, this.audio.context.sampleRate);
                        const output = buffer.getChannelData(0);
                        let lastOut = 0;
                        for (let i = 0; i < bufferSize; i++) {
                            const white = Math.random() * 2 - 1;
                            output[i] = (lastOut + (0.02 * white)) / 1.02; lastOut = output[i]; output[i] *= 3.5;
                        }
                        const noise = this.audio.context.createBufferSource();
                        noise.buffer = buffer; noise.loop = true; noise.start(0);
                        sound.node = noise;
                    } else {
                        const osc = this.audio.context.createOscillator();
                        osc.type = def.type; osc.frequency.setValueAtTime(def.freq, this.audio.context.currentTime); osc.start();
                        sound.node = osc;
                    }

                    if (def.filter) {
                        const filter = this.audio.context.createBiquadFilter();
                        filter.type = 'lowpass'; filter.frequency.setValueAtTime(def.filter, this.audio.context.currentTime);
                        sound.node.connect(filter); filter.connect(gainNode);
                    } else {
                        sound.node.connect(gainNode);
                    }
                    this.audio.sounds.push(sound);
                });
                this.state.audioInitialized = true;
            }

            updateAudioAmbience() {
                if (!this.state.audioInitialized) return;
                this.audio.sounds.forEach((sound, index) => {
                    const targetGain = (index === this.state.currentLevel) ? 0.5 : 0;
                    sound.gainNode.gain.linearRampToValueAtTime(targetGain, this.audio.context.currentTime + 1.5);
                });
            }

            // --- Starfield Canvas ---
            initStarfield() {
                this.resizeStarfield();
                this.createStars();
                this.animateStarfield();
            }

            resizeStarfield() {
                this.dom.starfieldCanvas.width = window.innerWidth;
                this.dom.starfieldCanvas.height = window.innerHeight;
            }

            createStars() {
                this.stars = [];
                for (let i = 0; i < this.constants.STAR_COUNT; i++) {
                    this.stars.push({
                        x: Math.random() * this.dom.starfieldCanvas.width,
                        y: Math.random() * this.dom.starfieldCanvas.height,
                        radius: Math.random() * 1.2 + 0.5,
                        alpha: Math.random() * 0.5 + 0.5,
                        z: Math.random() * 3 + 0.5
                    });
                }
            }

            animateStarfield() {
                const speed = 0.05 + (this.state.currentLevel * 0.05);
                this.stars.forEach(star => {
                    star.y -= speed * star.z;
                    if (star.y < 0) {
                        star.y = this.dom.starfieldCanvas.height;
                        star.x = Math.random() * this.dom.starfieldCanvas.width;
                    }
                });

                this.starfieldCtx.clearRect(0, 0, this.dom.starfieldCanvas.width, this.dom.starfieldCanvas.height);
                this.starfieldCtx.fillStyle = 'white';
                this.stars.forEach(star => {
                    this.starfieldCtx.beginPath();
                    this.starfieldCtx.arc(star.x, star.y, star.radius, 0, Math.PI * 2);
                    this.starfieldCtx.globalAlpha = star.alpha;
                    this.starfieldCtx.fill();
                });
                this.starfieldCtx.globalAlpha = 1.0;

                requestAnimationFrame(this.animateStarfield.bind(this));
            }

            // --- Utilities ---
            debounce(func, delay) {
                let timeout;
                return function(...args) {
                    clearTimeout(timeout);
                    timeout = setTimeout(() => func.apply(this, args), delay);
                };
            }
        }

        document.addEventListener('DOMContentLoaded', () => {
            new CosmicJourney();
        });
    </script>
</body>
