                const soundDefs = [
                    { type: 'sine', freq: 40, gain: 0.5 }, // Level 0: Deep space
                    { type: 'sawtooth', freq: 60, gain: 0.2, filter: 400 }, // Level 1: Local Group
                    { type: 'triangle', freq: 120, gain: 0.3, lfo: 5 }, // Level 2: Galaxy
                    { type: 'pink-noise', gain: 0.15 }, // Level 3: Nebula
                    { type: 'square', freq: 220, gain: 0.2, lfo: 10 }, // Level 4: Solar System
                    { type: 'sine', freq: 80, gain: 0.4 } // Level 5: End
                ];

                soundDefs.forEach(def => {
                    const sound = {};
                    const gainNode = audioCtx.createGain();
                    gainNode.gain.setValueAtTime(0, audioCtx.currentTime);
                    gainNode.connect(masterGain);
                    sound.gainNode = gainNode;

                    if (def.type.includes('noise')) {
                        const bufferSize = 2 * audioCtx.sampleRate;
                        const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
                        const output = buffer.getChannelData(0);
                        let lastOut = 0;
                        for (let i = 0; i < bufferSize; i++) {
                            const white = Math.random() * 2 - 1;
                            output[i] = (lastOut + (0.02 * white)) / 1.02;
                            lastOut = output[i];
                            output[i] *= 3.5; // (arbitrary) gain factor
                        }
                        const noise = audioCtx.createBufferSource();
                        noise.buffer = buffer;
                        noise.loop = true;
                        noise.start(0);
                        sound.node = noise;
