                setTimeout(() => { isAnimating = false; }, parseFloat(getComputedStyle(document.documentElement).getPropertyValue('--transition-speed')) * 1000);
            }

            function changeLevel(newLevel) {
                if (isAnimating || newLevel < 0 || newLevel >= NUM_LEVELS) return;
                initAudioOnFirstInteraction();
                currentLevel = newLevel;
