    "search_block": "<script>\n        document.addEventListener('DOMContentLoaded', () => {\n            // DOM Elements\n            const universe = document.getElementById('universe');\n            const zoomLevels = Array.from(document.querySelectorAll('.zoom-level'));\n            const uiContainer = document.getElementById('ui-container');\n            const scrollPrompt = document.getElementById('scroll-prompt');\n            const resetButton = document.getElementById('reset-button');\n            const liveRegion = document.getElementById('live-region');\n            const scaleNavigator = document.getElementById('scale-navigator');\n            const modalContainer = document.getElementById('modal-container');\n            const modalTitle = document.getElementById('modal-title');\n            const modalInfo = document.getElementById('modal-info');\n            const modalClose = document.querySelector('.modal-close');\n            const canvas = document.getElementById('starfield');\n            const ctx = canvas.getContext('2d');\n\n            // Constants & State\n            const ZOOM_FACTOR = parseFloat(getComputedStyle(document.documentElement).getPropertyValue('--zoom-factor')) || 50;\n            const NUM_LEVELS = zoomLevels.length;\n            let currentLevel = 0;\n            let isAnimating = false;\n            let touchStartY = 0;\n\n            // --- Web Audio API Setup ---\n            let audioCtx, masterGain, sounds = [];\n            let audioInitialized = false;\n\n            function setupAudio() {\n                if (audioInitialized) return;\n                audioCtx = new (window.AudioContext || window.webkitAudioContext)();\n                masterGain = audioCtx.createGain();\n                masterGain.gain.setValueAtTime(0.3, audioCtx.currentTime);\n                masterGain.connect(audioCtx.destination);\n\n                // Define sounds for each level\n                const soundDefs = [\n                    { type: 'sine', freq: 40, gain: 0.5 }, // Level 0: Deep space\n                    { type: 'sawtooth', freq: 60, gain: 0.2, filter: 400 }, // Level 1: Local Group\n                    { type: 'triangle', freq: 120, gain: 0.3, lfo: 5 }, // Level 2: Galaxy\n                    { type: 'pink-noise', gain: 0.15 }, // Level 3: Nebula\n                    { type: 'square', freq: 220, gain: 0.2, lfo: 10 }, // Level 4: Solar System\n                    { type: 'sine', freq: 80, gain: 0.4 } // Level 5: End\n                ];\n\n                soundDefs.forEach(def => {\n                    const sound = {};\n                    const gainNode = audioCtx.createGain();\n                    gainNode.gain.setValueAtTime(0, audioCtx.currentTime);\n                    gainNode.connect(masterGain);\n                    sound.gainNode = gainNode;\n\n                    if (def.type.includes('noise')) {\n                        const bufferSize = 2 * audioCtx.sampleRate;\n                        const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);\n                        const output = buffer.getChannelData(0);\n                        let lastOut = 0;\n                        for (let i = 0; i < bufferSize; i++) {\n                            const white = Math.random() * 2 - 1;\n                            output[i] = (lastOut + (0.02 * white)) / 1.02;\n                            lastOut = output[i];\n                            output[i] *= 3.5; // (arbitrary) gain factor\n                        }\n                        const noise = audioCtx.createBufferSource();\n                        noise.buffer = buffer;\n                        noise.loop = true;\n                        noise.start(0);\n                        sound.node = noise;\n                    } else {\n                        const osc = audioCtx.createOscillator();\n                        osc.type = def.type;\n                        osc.frequency.setValueAtTime(def.freq, audioCtx.currentTime);\n                        osc.start();\n                        sound.node = osc;\n                    }\n\n                    if (def.filter) {\n                        const filter = audioCtx.createBiquadFilter();\n                        filter.type = 'lowpass';\n                        filter.frequency.setValueAtTime(def.filter, audioCtx.currentTime);\n                        sound.node.connect(filter);\n                        filter.connect(gainNode);\n                    } else {\n                        sound.node.connect(gainNode);\n                    }\n                    sounds.push(sound);\n                });\n                audioInitialized = true;\n            }\n\n            function updateAudio() {\n                if (!audioInitialized) return;\n                sounds.forEach((sound, index) => {\n                    const targetGain = (index === currentLevel) ? 0.5 : 0;\n                    sound.gainNode.gain.linearRampToValueAtTime(targetGain, audioCtx.currentTime + 1.5);\n                });\n            }\n\n            function initAudioOnFirstInteraction() {\n                if (!audioInitialized) setupAudio();\n                if (audioCtx.state === 'suspended') audioCtx.resume();\n                updateAudio();\n            }\n\n            // --- Canvas Starfield --- \n            let stars = [];\n            function resizeCanvas() {\n                canvas.width = window.innerWidth;\n                canvas.height = window.innerHeight;\n            }\n\n            function createStars() {\n                stars = [];\n                for (let i = 0; i < 500; i++) {\n                    stars.push({\n                        x: Math.random() * canvas.width,\n                        y: Math.random() * canvas.height,\n                        radius: Math.random() * 1.2 + 0.5,\n                        alpha: Math.random() * 0.5 + 0.5,\n                        z: Math.random() * 3 // Parallax layers\n                    });\n                }\n            }\n\n            function drawStars() {\n                ctx.clearRect(0, 0, canvas.width, canvas.height);\n                ctx.fillStyle = 'white';\n                stars.forEach(star => {\n                    ctx.beginPath();\n                    ctx.arc(star.x, star.y, star.radius, 0, Math.PI * 2);\n                    ctx.globalAlpha = star.alpha;\n                    ctx.fill();\n                });\n                ctx.globalAlpha = 1.0;\n            }\n\n            function updateStars() {\n                const speed = 0.05 + (currentLevel * 0.05);\n                stars.forEach(star => {\n                    star.y -= speed * star.z;\n                    if (star.y < 0) {\n                        star.y = canvas.height;\n                        star.x = Math.random() * canvas.width;\n                    }\n                });\n            }\n\n            function animate() {\n                updateStars();\n                drawStars();\n                requestAnimationFrame(animate);\n            }\n\n            // --- Core Application Logic ---\n            function updateUniverse() {\n                isAnimating = true;\n\n                zoomLevels.forEach((level, index) => {\n                    level.classList.toggle('active', index === currentLevel);\n                    level.setAttribute('aria-hidden', index !== currentLevel);\n                });\n\n                const activeLevel = zoomLevels[currentLevel];\n                const levelLabel = activeLevel.getAttribute('aria-label');\n                if (levelLabel) liveRegion.textContent = `Now viewing: ${levelLabel}`;\n\n                const totalScale = Math.pow(ZOOM_FACTOR, currentLevel);\n                const universeZ = currentLevel * -1000;\n                universe.style.transform = `translateZ(${universeZ}px) scale(${totalScale})`;\n\n                zoomLevels.forEach((level, index) => {\n                    const levelScale = Math.pow(ZOOM_FACTOR, -index);\n                    level.style.transform = `scale(${levelScale})`;\n                    level.style.opacity = (index >= currentLevel) ? '1' : '0';\n                });\n\n                // Update UI\n                scrollPrompt.style.display = (currentLevel === 0) ? 'block' : 'none';\n                resetButton.classList.toggle('visible', currentLevel > 0);\n                uiContainer.classList.toggle('hidden', currentLevel === NUM_LEVELS - 1);\n                document.querySelectorAll('.nav-dot').forEach((dot, index) => {\n                    dot.classList.toggle('active', index === currentLevel);\n                });\n\n                updateAudio();\n\n                setTimeout(() => { isAnimating = false; }, parseFloat(getComputedStyle(document.documentElement).getPropertyValue('--transition-speed')) * 1000);\n            }\n\n            function changeLevel(newLevel) {\n                if (isAnimating || newLevel < 0 || newLevel >= NUM_LEVELS) return;\n                initAudioOnFirstInteraction();\n                currentLevel = newLevel;\n                updateUniverse();\n            }\n\n            function zoomIn() { changeLevel(currentLevel + 1); }\n            function zoomOut() { changeLevel(currentLevel - 1); }\n            function resetZoom() { changeLevel(0); }\n\n            // --- Event Listeners ---\n            window.addEventListener('wheel', event => {\n                if (isAnimating) return;\n                event.preventDefault();\n                if (event.deltaY > 0) zoomIn();\n                else zoomOut();\n            }, { passive: false });\n\n            window.addEventListener('keydown', event => {\n                if (isAnimating) return;\n                if (event.key === 'ArrowDown' || event.key === 'PageDown') { event.preventDefault(); zoomIn(); }\n                if (event.key === 'ArrowUp' || event.key === 'PageUp') { event.preventDefault(); zoomOut(); }\n                if (event.key === 'Home') { event.preventDefault(); resetZoom(); }\n                if (event.key === 'Escape' && !modalContainer.classList.contains('hidden')) hideModal();\n            });\n\n            window.addEventListener('touchstart', e => { touchStartY = e.touches[0].clientY; }, { passive: true });\n            window.addEventListener('touchmove', e => {\n                if (isAnimating) return;\n                const touchEndY = e.changedTouches[0].clientY;\n                if (touchStartY - touchEndY > 50) { zoomIn(); touchStartY = touchEndY; }\n                if (touchEndY - touchStartY > 50) { zoomOut(); touchStartY = touchEndY; }\n            }, { passive: true });\n\n            resetButton.addEventListener('click', resetZoom);\n\n            // --- Modal & POI Logic ---\n            function showModal(title, info) {\n                modalTitle.textContent = title;\n                modalInfo.textContent = info;\n                modalContainer.classList.remove('hidden');\n                modalClose.focus();\n            }\n\n            function hideModal() {\n                modalContainer.classList.add('hidden');\n            }\n\n            modalContainer.addEventListener('click', (e) => { if (e.target === modalContainer) hideModal(); });\n            modalClose.addEventListener('click', hideModal);\n\n            document.querySelectorAll('.poi').forEach(poi => {\n                const title = poi.dataset.title;\n                const tooltip = document.createElement('div');\n                tooltip.className = 'tooltip';\n                tooltip.textContent = title;\n                poi.appendChild(tooltip);\n                poi.setAttribute('aria-label', `Point of Interest: ${title}`);\n                poi.setAttribute('role', 'button');\n                poi.tabIndex = 0;\n\n                poi.addEventListener('click', () => showModal(title, poi.dataset.info));\n                poi.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') showModal(title, poi.dataset.info); });\n            });\n\n            // --- Initial Setup ---\n            function init() {\n                zoomLevels.forEach((level, index) => {\n                    const scale = Math.pow(ZOOM_FACTOR, -index);\n                    level.style.transform = `scale(${scale})`;\n\n                    const dot = document.createElement('button');\n                    dot.className = 'nav-dot';\n                    dot.setAttribute('aria-label', `Jump to ${level.getAttribute('aria-label')}`);\n                    dot.addEventListener('click', () => changeLevel(index));\n                    const tooltip = document.createElement('span');\n                    tooltip.className = 'tooltip';\n                    tooltip.textContent = level.getAttribute('aria-label');\n                    dot.appendChild(tooltip);\n                    scaleNavigator.appendChild(dot);\n                });\n\n                zoomLevels[0].classList.add('active');\n                document.querySelector('.nav-dot').classList.add('active');\n                liveRegion.textContent = `Now viewing: ${zoomLevels[0].getAttribute('aria-label')}`;\n\n                resizeCanvas();\n                createStars();\n                animate();\n                window.addEventListener('resize', () => { resizeCanvas(); createStars(); });\n            }\n\n            init();\n        });\n    </script>",
    "replace_with": "<script>\n        class CosmicJourney {\n            constructor() {\n                this.cacheDOMElements();\n                this.initState();\n                this.initStarfield();\n                this.initUI();\n                this.bindEventListeners();\n            }\n\n            cacheDOMElements() {\n                this.dom = {\n                    loadingOverlay: document.getElementById('loading-overlay'),\n                    startButton: document.querySelector('.start-button'),\n                    universe: document.getElementById('universe'),\n                    zoomLevels: Array.from(document.querySelectorAll('.zoom-level')),\n                    uiContainer: document.getElementById('ui-container'),\n                    scrollPrompt: document.getElementById('scroll-prompt'),\n                    resetButton: document.getElementById('reset-button'),\n                    liveRegion: document.getElementById('live-region'),\n                    scaleNavigator: document.getElementById('scale-navigator'),\n                    modalContainer: document.getElementById('modal-container'),\n                    modalTitle: document.getElementById('modal-title'),\n                    modalInfo: document.getElementById('modal-info'),\n                    modalClose: document.querySelector('.modal-close'),\n                    starfieldCanvas: document.getElementById('starfield'),\n                };\n                this.starfieldCtx = this.dom.starfieldCanvas.getContext('2d');\n            }\n\n            initState() {\n                const styles = getComputedStyle(document.documentElement);\n                this.constants = {\n                    ZOOM_FACTOR: parseFloat(styles.getPropertyValue('--zoom-factor')) || 50,\n                    TRANSITION_SPEED: parseFloat(styles.getPropertyValue('--transition-speed')) * 1000 || 1600,\n                    NUM_LEVELS: this.dom.zoomLevels.length,\n                    STAR_COUNT: 500,\n                };\n                this.state = {\n                    currentLevel: 0,\n                    isAnimating: false,\n                    touchStartY: 0,\n                    audioInitialized: false,\n                    modalOpen: false,\n                    lastFocusedElement: null,\n                };\n                this.audio = { context: null, masterGain: null, sounds: [] };\n                this.stars = [];\n            }\n\n            initUI() {\n                this.dom.zoomLevels.forEach((level, index) => {\n                    const scale = Math.pow(this.constants.ZOOM_FACTOR, -index);\n                    level.style.transform = `scale(${scale})`;\n                    const levelTitleElement = level.querySelector('h1, h2');\n                    const levelTitle = levelTitleElement ? levelTitleElement.textContent : `Level ${index}`;\n                    level.setAttribute('aria-labelledby', levelTitleElement.id);\n\n                    const dot = document.createElement('button');\n                    dot.className = 'nav-dot';\n                    dot.setAttribute('aria-label', `Jump to ${levelTitle}`);\n                    dot.addEventListener('click', () => this.changeLevel(index));\n                    const tooltip = document.createElement('span');\n                    tooltip.className = 'tooltip';\n                    tooltip.textContent = levelTitle;\n                    dot.appendChild(tooltip);\n                    this.dom.scaleNavigator.appendChild(dot);\n                });\n\n                this.dom.zoomLevels[0].classList.add('active');\n                this.dom.scaleNavigator.querySelector('.nav-dot').classList.add('active');\n                this.updateLiveRegion();\n\n                document.querySelectorAll('.poi').forEach(poi => {\n                    const title = poi.dataset.title;\n                    const tooltip = document.createElement('div');\n                    tooltip.className = 'tooltip';\n                    tooltip.textContent = title;\n                    poi.appendChild(tooltip);\n                    poi.setAttribute('aria-label', `Point of Interest: ${title}`);\n                    poi.addEventListener('click', () => this.showModal(title, poi.dataset.info, poi));\n                });\n            }\n\n            bindEventListeners() {\n                this.dom.startButton.addEventListener('click', () => this.startExperience());\n                window.addEventListener('wheel', this.debounce(this.handleWheel.bind(this), 50), { passive: false });\n                window.addEventListener('keydown', this.handleKeyDown.bind(this));\n                window.addEventListener('touchstart', e => { this.state.touchStartY = e.touches[0].clientY; }, { passive: true });\n                window.addEventListener('touchmove', this.handleTouchMove.bind(this), { passive: true });\n                this.dom.resetButton.addEventListener('click', () => this.resetZoom());\n                this.dom.modalContainer.addEventListener('click', e => { if (e.target === this.dom.modalContainer) this.hideModal(); });\n                this.dom.modalClose.addEventListener('click', () => this.hideModal());\n                window.addEventListener('resize', this.debounce(() => {\n                    this.resizeStarfield();\n                    this.createStars();\n                }, 250));\n            }\n\n            startExperience() {\n                this.dom.loadingOverlay.classList.add('hidden');\n                this.initAudio();\n                this.updateAudioAmbience();\n            }\n\n            // --- Core Logic ---\n            changeLevel(newLevel) {\n                if (this.state.isAnimating || newLevel < 0 || newLevel >= this.constants.NUM_LEVELS || newLevel === this.state.currentLevel) return;\n                this.state.currentLevel = newLevel;\n                this.updateUniverse();\n            }\n\n            updateUniverse() {\n                this.state.isAnimating = true;\n\n                this.dom.zoomLevels.forEach((level, index) => {\n                    level.classList.toggle('active', index === this.state.currentLevel);\n                    level.setAttribute('aria-hidden', index !== this.state.currentLevel);\n                });\n\n                const totalScale = Math.pow(this.constants.ZOOM_FACTOR, this.state.currentLevel);\n                const universeZ = this.state.currentLevel * -1000;\n                this.dom.universe.style.transform = `translateZ(${universeZ}px) scale(${totalScale})`;\n\n                this.dom.zoomLevels.forEach((level, index) => {\n                    const levelScale = Math.pow(this.constants.ZOOM_FACTOR, -index);\n                    level.style.transform = `scale(${levelScale})`;\n                    level.style.opacity = (index >= this.state.currentLevel) ? '1' : '0';\n                });\n\n                this.updateUIState();\n                this.updateAudioAmbience();\n                this.preloadNextImage();\n\n                setTimeout(() => { this.state.isAnimating = false; }, this.constants.TRANSITION_SPEED);\n            }\n\n            updateUIState() {\n                this.dom.scrollPrompt.style.display = (this.state.currentLevel === 0) ? 'block' : 'none';\n                this.dom.resetButton.classList.toggle('visible', this.state.currentLevel > 0);\n                this.dom.uiContainer.classList.toggle('hidden', this.state.currentLevel === this.constants.NUM_LEVELS - 1);\n                this.dom.scaleNavigator.querySelectorAll('.nav-dot').forEach((dot, index) => {\n                    dot.classList.toggle('active', index === this.state.currentLevel);\n                });\n                this.updateLiveRegion();\n            }\n\n            updateLiveRegion() {\n                const activeLevel = this.dom.zoomLevels[this.state.currentLevel];\n                const levelTitle = document.getElementById(activeLevel.getAttribute('aria-labelledby')).textContent;\n                this.dom.liveRegion.textContent = `Now viewing: ${levelTitle}`;\n            }\n\n            preloadNextImage() {\n                const nextLevel = this.state.currentLevel + 1;\n                if (nextLevel < this.constants.NUM_LEVELS) {\n                    const nextImg = this.dom.zoomLevels[nextLevel].querySelector('.visual');\n                    if (nextImg && nextImg.src) {\n                        const img = new Image();\n                        img.src = nextImg.src;\n                    }\n                }\n            }\n\n            // --- Event Handlers ---\n            handleWheel(event) {\n                if (this.state.isAnimating || this.state.modalOpen) return;\n                event.preventDefault();\n                if (event.deltaY > 0) this.zoomIn();\n                else this.zoomOut();\n            }\n\n            handleKeyDown(event) {\n                if (this.state.isAnimating && event.key !== 'Escape') return;\n                if (this.state.modalOpen) {\n                    if (event.key === 'Escape') this.hideModal();\n                    if (event.key === 'Tab') this.trapFocus(event);\n                    return;\n                }\n                const keyMap = {\n                    'ArrowDown': () => this.zoomIn(),\n                    'PageDown': () => this.zoomIn(),\n                    'ArrowUp': () => this.zoomOut(),\n                    'PageUp': () => this.zoomOut(),\n                    'Home': () => this.resetZoom(),\n                    'End': () => this.changeLevel(this.constants.NUM_LEVELS - 1),\n                };\n                if (keyMap[event.key]) {\n                    event.preventDefault();\n                    keyMap[event.key]();\n                }\n            }\n\n            handleTouchMove(e) {\n                if (this.state.isAnimating || this.state.modalOpen) return;\n                const touchEndY = e.changedTouches[0].clientY;\n                const deltaY = this.state.touchStartY - touchEndY;