                    stars.push({
                        x: Math.random() * canvas.width,
                        y: Math.random() * canvas.height,
                        radius: Math.random() * 1.5 + 0.5,
                        alpha: Math.random(),
                        velocity: Math.random() * 0.1 + 0.05
                    });
                }
