                        })
                    }
                }
            });

            // Animate scroll prompt out
            mainTimeline.to('.scroll-prompt', { autoAlpha: 0 }, 0);

            // Intro -> Galaxy
            mainTimeline
                .to('#intro .zoom-content', { scale: 0.1, autoAlpha: 0, duration: 2 })
