                .fromTo('#earth .zoom-content', 
                    { scale: 0.1, autoAlpha: 0 }, 
                    { scale: 1, autoAlpha: 1, duration: 3, onStart: () => announcer.textContent = 'Now viewing: Planet Earth' }, 
                    '-=1.5')

            // Earth -> Outro
                .to('#earth .zoom-content', { scale: 0.2, autoAlpha: 0, duration: 2 }, '+=2')
                .fromTo('#outro .zoom-content', 
                    { autoAlpha: 0 }, 
                    { autoAlpha: 1, duration: 2, onStart: () => announcer.textContent = 'Now viewing: The Journey Continues' }, 
                    '-=1');

