                        scrollTo: { y: targetSection, offsetY: window.innerHeight / 2 },
                        duration: 1.5,
                        ease: 'power2.inOut'
                    });
                });
            });

            document.getElementById('reset-zoom').addEventListener('click', () => {
                gsap.to(window, { scrollTo: 0, duration: 2, ease: 'power2.inOut' });
            });
        });
