        document.addEventListener('DOMContentLoaded', () => {
            const universe = document.getElementById('universe-canvas');
            const zoomLayers = Array.from(document.querySelectorAll('.zoom-layer'));
            const scrollPrompt = document.querySelector('.scroll-prompt');
            const resetButton = document.getElementById('reset-zoom');
            const announcer = document.getElementById('sr-announcer');

            const MAX_ZOOM = 150;
            let currentZoom = 0;
            let activeLayer = zoomLayers[0];
            let animationFrameId = null;

            function updateUniverseState() {
                const scale = 1 + (currentZoom / 50);
                universe.style.setProperty('--scale-factor', scale);

                let currentlyVisibleLayer = null;

                zoomLayers.forEach(layer => {
                    const minZoom = parseFloat(layer.dataset.minZoom);
                    const maxZoom = parseFloat(layer.dataset.maxZoom);

                    if (currentZoom >= minZoom && currentZoom <= maxZoom) {
                        currentlyVisibleLayer = layer;
                    }
                });

                if (currentlyVisibleLayer && currentlyVisibleLayer !== activeLayer) {
                    if(activeLayer) {
                        activeLayer.classList.remove('is-active');
                        activeLayer.setAttribute('aria-hidden', 'true');
                    }
                    currentlyVisibleLayer.classList.add('is-active');
                    currentlyVisibleLayer.setAttribute('aria-hidden', 'false');
                    activeLayer = currentlyVisibleLayer;

                    const title = activeLayer.querySelector('h1, h2').textContent;
                    announcer.textContent = `Now viewing: ${title}`;
                }

                if (currentZoom > 5 && !scrollPrompt.classList.contains('hidden')) {
                    scrollPrompt.classList.add('hidden');
                } else if (currentZoom <= 5 && scrollPrompt.classList.contains('hidden')) {
                    scrollPrompt.classList.remove('hidden');
                }
                animationFrameId = null;
            }

            function requestUpdate() {
                if (!animationFrameId) {
                    animationFrameId = requestAnimationFrame(updateUniverseState);
                }
            }

            function handleZoom(delta) {
                const zoomAmount = delta * 0.5;
                currentZoom += zoomAmount;
                currentZoom = Math.max(0, Math.min(MAX_ZOOM, currentZoom));
                requestUpdate();
            }

            function handleScroll(event) {
                event.preventDefault();
                handleZoom(event.deltaY > 0 ? 1 : -1);
            }

            function handleKeyDown(event) {
                if (event.key === 'ArrowDown' || event.key === ' ') {
                    event.preventDefault();
                    handleZoom(2); // Larger jump for keyboard
                } else if (event.key === 'ArrowUp') {
                    event.preventDefault();
                    handleZoom(-2);
                }
            }

            function resetJourney() {
                currentZoom = 0;
                requestUpdate();
            }

            window.addEventListener('wheel', handleScroll, { passive: false });
            window.addEventListener('keydown', handleKeyDown);
            resetButton.addEventListener('click', resetJourney);

            updateUniverseState(); // Initial setup
        });
    </script>
