                        modalImg.alt = data.alt;
                        App.DOM.modal.querySelector('#modal-title').textContent = data.title;
                        App.DOM.modal.querySelector('#modal-description').textContent = data.description;

                        App.DOM.modal.showModal();
                        App.STATE.setState({ isModalOpen: true });
