            /**
             * --------------------------------
             * Focus Trap Utility
             * --------------------------------
             * Manages focus within a specified element, crucial for modal accessibility.
             */
            class FocusTrap {
                constructor(element) {
                    this.element = element;
                    this.focusableElements = [];
                    this.firstFocusableElement = null;
                    this.lastFocusableElement = null;
                    this.handleKeyDown = this.handleKeyDown.bind(this);
                }

                activate() {
                    const focusableSelectors = 'a[href], button, input, textarea, select, details, [tabindex]:not([tabindex="-1"])';
                    this.focusableElements = Array.from(this.element.querySelectorAll(focusableSelectors)).filter(el => !el.disabled && el.offsetParent !== null);
                    if (this.focusableElements.length === 0) return;
                    this.firstFocusableElement = this.focusableElements[0];
                    this.lastFocusableElement = this.focusableElements[this.focusableElements.length - 1];
                    this.element.addEventListener('keydown', this.handleKeyDown);
                    this.firstFocusableElement.focus();
                }

                deactivate() {
                    this.element.removeEventListener('keydown', this.handleKeyDown);
                }

                handleKeyDown(e) {
                    if (e.key !== 'Tab') return;

                    if (e.shiftKey) { // Shift + Tab
                        if (document.activeElement === this.firstFocusableElement) {
                            e.preventDefault();
                            this.lastFocusableElement.focus();
                        }
                    } else { // Tab
                        if (document.activeElement === this.lastFocusableElement) {
                            e.preventDefault();
                            this.firstFocusableElement.focus();
                        }
                    }
                }
            }"
