    "new_content": "
        .poi-beacon {
            animation-duration: 1.5s;
        }

        @keyframes pulse-poi {
            0%, 100% { box-shadow: 0 0 5px var(--color-secondary), 0 0 10px var(--color-glow-light); }
            50% { box-shadow: 0 0 15px var(--color-secondary), 0 0 25px var(--color-glow-light); }
        }

        .poi.poi-beacon::after {
            content: '';
            position: absolute;
            top: -6px; left: -6px; right: -6px; bottom: -6px;
            border-radius: 50%;
            border: 2px solid var(--color-accent);
            animation: pulse-beacon 1.5s infinite ease-in-out;
            pointer-events: none;
        }

        @keyframes pulse-beacon {
            0% { transform: scale(0.8); opacity: 0.5; }
            50% { opacity: 1; }
            100% { transform: scale(1.5); opacity: 0; }
        }"
