            position: fixed;
            top: 50%;
            right: 2rem;
            transform: translateY(-50%);
            z-index: var(--z-ui);
        }

        .cosmic-timeline-list {
            display: flex;
            flex-direction: column;
            gap: 1.5rem;
            list-style: none;
        }
        .timeline-node {
            width: 20px;
            height: 20px;
            appearance: none;
            background-color: transparent;
            border: 2px solid var(--color-primary);
            border-radius: 50%;
            cursor: pointer;
            position: relative;
            transition: background-color 0.3s var(--ease-in-out-cubic), transform 0.3s var(--ease-out-quart);
            display: block;
            padding: 0;
        }
        .timeline-node:hover,
        .timeline-node:focus-visible,
        .timeline-node[aria-current="true"] {
            background-color: var(--color-primary);
            transform: scale(1.3);
            box-shadow: 0 0 15px var(--color-primary);
        }
        .timeline-node:focus-visible { 
            outline: var(--focus-outline-width) solid var(--color-accent);
            outline-offset: var(--focus-outline-offset);
        }
        .timeline-label {
            position: absolute;
            right: 180%;
            top: 50%;
            transform: translateY(-50%) translateX(0.5rem);
            color: var(--color-text-primary);
            background: var(--color-background-med);
            padding: 0.3rem 0.7rem;
            border-radius: var(--radius-sm);
            white-space: nowrap;
            opacity: 0;
            visibility: hidden;
            transition: all 0.3s var(--ease-out-quart);
            pointer-events: none;
            border: 1px solid rgba(167, 181, 255, 0.2);
        }
        .timeline-node:hover .timeline-label,
        .timeline-node:focus-visible .timeline-label {
            opacity: 1;
            visibility: visible;
            transform: translateY(-50%) translateX(-0.5rem);
        }

        /* API Content */
        #api-corner {
            position: fixed;
            top: 1.5rem;
            left: 1.5rem;
            z-index: var(--z-ui);
            background: rgba(10, 11, 26, 0.7);
            backdrop-filter: blur(8px);
            padding: 0.75rem 1.25rem;
            border-radius: var(--radius-md);
            font-size: 0.9rem;
            border: 1px solid rgba(167, 181, 255, 0.2);
            transition: opacity 0.3s, transform 0.3s var(--ease-out-quart);
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }
        #apod-container {
            margin-top: 2rem;
            max-width: 500px;
            width: 100%;
            border: 1px solid var(--color-primary);
            padding: 1.5rem;
            border-radius: var(--radius-lg);
            background: rgba(10, 11, 26, 0.5);
            backdrop-filter: blur(3px);
            text-align: left;
            min-height: 200px; /* For loading state */
            display: flex;
            flex-direction: column;
            justify-content: center;
        }
        #apod-container img {
            max-width: 100%;
            border-radius: var(--radius-sm);
        }
        #apod-container figcaption {
            font-size: 0.9rem;
            margin-top: 0.75rem;
            color: var(--color-text-secondary);
            line-height: 1.5;
        }
        #apod-container figcaption strong {
            color: var(--color-secondary);
            display: block;
            margin-bottom: 0.25rem;
        }

        @keyframes slide-clouds {
            from { transform: translateX(0); }
            to { transform: translateX(-300px); }
        }

        /* UI Elements */
        .scroll-prompt {
            position: fixed;
            bottom: 2rem;
            left: 50%;
            transform: translateX(-50%);
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0.5rem;
            color: var(--color-primary);
            opacity: 0;
            transition: opacity 0.5s ease;
            z-index: var(--z-ui);
            pointer-events: none;
            animation: fade-in-prompt 1s 2s ease forwards;
        }
        @keyframes fade-in-prompt {
            to { opacity: 1; }
        }
        .scroll-prompt.hidden {
            opacity: 0;
        }
        .scroll-mouse {
            width: 24px;
            height: 40px;
            border: 2px solid var(--color-primary);
            border-radius: 12px;
            position: relative;
            margin-bottom: 0.5rem;
        }
        .scroll-wheel {
            width: 4px;
            height: 8px;
            background-color: var(--color-primary);
            border-radius: 2px;
            position: absolute;
            top: 6px;
            left: 50%;
            transform: translateX(-50%);
            animation: scroll-anim 2s infinite;
        }
        @keyframes scroll-anim {
            0% { transform: translate(-50%, 0); opacity: 1; }
            50% { transform: translate(-50%, 10px); opacity: 1; }
            100% { transform: translate(-50%, 20px); opacity: 0; }
        }

        .cta-button {
            background: transparent;
            border: 2px solid var(--color-primary);
            color: var(--color-primary);
            padding: 0.75rem 1.5rem;
            font-size: 1rem;
            text-transform: uppercase;
            letter-spacing: 0.1em;
            cursor: pointer;
            transition: all 0.3s ease;
            margin-top: 2rem;
            box-shadow: 0 0 5px var(--color-primary), inset 0 0 5px var(--color-primary);
            border-radius: var(--radius-sm);
            font-weight: 700;
            font-family: var(--font-sans);
        }
        .cta-button:hover, .cta-button:focus-visible {
            background-color: var(--color-primary);
            color: var(--color-background-deep);
            box-shadow: 0 0 25px var(--color-primary);
            outline: none;
        }
        .cta-button:focus-visible {
            outline: var(--focus-outline-width) solid var(--color-accent);
            outline-offset: var(--focus-outline-offset);
        }
        .cta-button:active {
            transform: translateY(1px) scale(0.98);
        }


        @media (prefers-reduced-motion: reduce) {
            *, *::before, *::after {
                animation-delay: -1ms !important;
                animation-duration: 1ms !important;
                animation-iteration-count: 1 !important;
                background-attachment: initial !important;
                scroll-behavior: auto !important;
                transition-delay: 0s !important;
                transition-duration: 0s !important;
            }
        }
        @media (max-width: 1024px) {
            .cosmic-timeline {
                right: 1.5rem;
            }
        }

        @media (max-width: 768px) {
            .cosmic-timeline {
                display: none; /* Replaced with a different nav concept for mobile */
            }

            #api-corner {
                flex-direction: row;
                flex-wrap: wrap;
                top: 1rem;
                left: 1rem;
                right: 1rem;
                justify-content: center;
            }

            .zoom-layer { padding: 1rem; }
            .zoom-content { gap: 1rem; }

            h2 { font-size: clamp(2rem, 10vw, 3rem); }
            .title { font-size: clamp(2.5rem, 12vw, 4rem); }
        }
