                    this.AUDIO_CONTROLLER.init();
                    this.MODAL_CONTROLLER.init();
                    this.initStarfield();
                    this.initNavigation();
                    this.initEventListeners();
                    this.setDailyBeacon();
                    await this.initAPIs();
                    this.initGSAP();
                    window.addEventListener('load', () => {
                         this.DOM.loader.classList.add('is-hidden');
                         this.DOM.body.classList.remove('is-loading');
                         this.DOM.body.classList.add('is-loaded');
                         this.STATE.setState({ isLoaded: true });
                    });
                },

                cacheDOM() {
                    this.DOM = {
                        body: document.body,
                        loader: document.getElementById('loader'),
                        starfieldCanvas: document.getElementById('starfield-canvas'),
                        announcer: document.getElementById('sr-announcer'),
                        timelineNodes: document.querySelectorAll('.timeline-node'),
                        sections: document.querySelectorAll('.zoom-layer'),
                        scrollPrompt: document.querySelector('.scroll-prompt'),
                        resetBtn: document.getElementById('reset-zoom'),
                        astronautCount: document.getElementById('astronaut-count'),
                        exoplanetBtn: document.getElementById('exoplanet-container'),
                        exoplanetCount: document.getElementById('exoplanet-count'),
                        apodContainer: document.getElementById('apod-container'),
                        muteBtn: document.getElementById('mute-toggle'),
                        // Modal elements are cached in its controller
                    };
                },

                debounce: (fn, delay) => { let t; return function(...a){ clearTimeout(t); t = setTimeout(() => fn.apply(this, a), delay); } },
                truncateText: (text, max) => text.length <= max ? text : text.substr(0, text.substr(0, max).lastIndexOf(' ')) + '…',

                setDailyBeacon() {
                    const dayOfYear = Math.floor((new Date() - new Date(new Date().getFullYear(), 0, 0)) / (1000 * 60 * 60 * 24));
                    const poiKeys = Object.keys(this.POI_DATA).filter(k => k !== 'exoplanet-info'); // Exclude non-discoverable POIs
                    const beaconKey = poiKeys[dayOfYear % poiKeys.length];
                    const beaconEl = document.querySelector(`[data-poi="${beaconKey}"]`);
                    if (beaconEl) beaconEl.classList.add('poi-beacon');
                },

                initStarfield() {
                    /* Starfield implementation remains largely the same */
                    const Starfield = {
                        canvas: this.DOM.starfieldCanvas, ctx: this.DOM.starfieldCanvas.getContext('2d'), stars: [], animId: null,
                        setup() {
                            const dpr = window.devicePixelRatio || 1;
                            const rect = this.canvas.getBoundingClientRect();
                            this.canvas.width = rect.width * dpr; this.canvas.height = rect.height * dpr;
                            this.ctx.scale(dpr, dpr);
                            const numStars = window.innerWidth > 768 ? 800 : 300;
                            this.stars = Array.from({ length: numStars }, () => ({ x: Math.random() * this.canvas.width/dpr, y: Math.random() * this.canvas.height/dpr, z: Math.random()*2+.5, r: Math.random()*1.2+.3, a: Math.random()*.5+.5 }));
