                        draw() {
                            if (!App.STATE.getState().isStarfieldPaused) {
                                const w = this.canvas.width / (window.devicePixelRatio||1), h = this.canvas.height / (window.devicePixelRatio||1);
                                this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height);
                                this.stars.forEach(s => {
                                    this.ctx.beginPath(); this.ctx.arc(s.x, s.y, s.r*s.z, 0, Math.PI*2); this.ctx.fillStyle = `rgba(255,255,255,${s.a})`; this.ctx.fill();
                                    s.y -= (0.1*s.z) + 0.05;
                                    if (s.y < 0) { s.y = h; s.x = Math.random()*w; }
