                },

                async initAPIs() {
                    await Promise.allSettled([
                        this.API_SERVICE.fetchAPOD(),
                        this.API_SERVICE.fetchAstronauts(),
                        this.API_SERVICE.fetchExoplanets()
                    ]);
                },

                initGSAP() {
                    gsap.registerPlugin(ScrollTrigger, ScrollToPlugin);
                    const sections = this.DOM.sections, numSections = sections.length, DURATION = 1.5, SCROLL_AMOUNT = window.innerHeight * 1.5;
                    this.masterTimeline = gsap.timeline({ scrollTrigger: { trigger: '#universe-container', pin: true, scrub: 1.5, end: `+=${numSections * SCROLL_AMOUNT}`, onUpdate: self => this.updateNavState(self.progress), onToggle: self => this.STATE.setState({ isScrolling: self.isActive }) } });
                    this.masterTimeline.to(this.DOM.scrollPrompt, { autoAlpha: 0 }, 0);
                    sections.forEach((section, i) => {
                        if (i === 0) return;
