                },

                initNavigation() {
                    const scrollToSection = (index) => {
                        const st = this.masterTimeline.scrollTrigger;
                        const targetScroll = index === 0 ? 0 : st.start + (st.end - st.start) * (index / (this.DOM.sections.length - 1.01));
