                    motionQuery.addEventListener('change', handleReducedMotion); handleReducedMotion();
                },
            };

            App.API_SERVICE = {
                async fetchWithCache(url, options = {}, key, ttl = 3600000) {
                    const cache = sessionStorage.getItem(key);
                    if (cache) { const { data, timestamp } = JSON.parse(cache); if (Date.now() - timestamp < ttl) return data; }
