                },
                async fetchAPOD() { try { const data = await this.fetchWithCache('https://api.nasa.gov/planetary/apod?api_key=DEMO_KEY', {}, 'apod'); App.DOM.apodContainer.innerHTML = `<img src="${data.hdurl || data.url}" alt="${data.title}" loading="lazy"><figcaption id="apod-caption"><strong>${data.title}</strong>${App.truncateText(data.explanation, 200)}</figcaption>`; } catch (e) { App.DOM.apodContainer.innerHTML = '<p>Could not connect to NASA\\'s image archive.</p>'; } },
                async fetchAstronauts() { try { const data = await this.fetchWithCache('https://cors-proxy.fcc-rest-apis.repl.co/api?url=http://api.open-notify.org/astros.json', {}, 'astronauts', 60000); App.DOM.astronautCount.textContent = data.number; } catch (e) { App.DOM.astronautCount.textContent = 'N/A'; App.DOM.astronautCount.parentElement.setAttribute('aria-label', 'Astronaut data unavailable'); } },
                async fetchExoplanets() { try { const data = await this.fetchWithCache('https://exoplanetarchive.ipac.caltech.edu/TAP/sync?query=select+count(pl_name)+from+pscomppars&format=json', {}, 'exoplanets'); App.DOM.exoplanetCount.textContent = data[0].count_pl_name.toLocaleString(); } catch (e) { App.DOM.exoplanetCount.textContent = 'N/A'; App.DOM.exoplanetBtn.disabled = true; App.DOM.exoplanetBtn.setAttribute('aria-label', 'Exoplanet data unavailable'); } },
            };

            App.AUDIO_CONTROLLER = {
                init() { this.sounds = { ambient: document.getElementById('audio-ambient'), zoom: document.getElementById('audio-zoom'), poi: document.getElementById('audio-poi'), modal: document.getElementById('audio-modal') }; this.sounds.ambient.volume = 0.3; this.sounds.zoom.volume = 0.5; },
                play(id) { if (!App.STATE.getState().isMuted && this.sounds[id]) { this.sounds[id].currentTime = 0; this.sounds[id].play(); } },
                playAmbient() { if (!App.STATE.getState().isMuted) this.sounds.ambient.play(); },
                toggleMute() {
                    const isMuted = !App.STATE.getState().isMuted;
                    App.STATE.setState({ isMuted });
                    Object.values(this.sounds).forEach(s => s.muted = isMuted);
                    App.DOM.muteBtn.classList.toggle('is-muted', isMuted);
                    App.DOM.muteBtn.setAttribute('aria-label', isMuted ? 'Unmute audio' : 'Mute audio');
                },
            };

            App.MODAL_CONTROLLER = {
                init() { this.dom = { dialog: document.getElementById('poi-modal'), title: document.getElementById('modal-title'), image: document.getElementById('modal-image'), contentArea: document.getElementById('modal-content-area'), closeBtn: document.querySelector('.modal-close') }; this.history = []; this.dom.dialog.addEventListener('click', e => e.target === this.dom.dialog && this.close()); this.dom.closeBtn.addEventListener('click', () => this.close()); this.dom.dialog.addEventListener('keydown', e => e.key === 'Escape' && this.close()); this.dom.contentArea.addEventListener('click', e => { if (e.target.matches('.db-link')) { e.preventDefault(); const key = e.target.dataset.key; this.navigateTo(key, App.COSMIC_DB); } if (e.target.matches('.modal-back-btn')) { e.preventDefault(); this.back(); } }); },
                open(poiId) { this.history = []; this.navigateTo(poiId, App.POI_DATA); App.AUDIO_CONTROLLER.play('modal'); this.dom.dialog.showModal(); App.STATE.setState({ isModalOpen: true }); },
                close() { this.dom.dialog.close(); App.STATE.setState({ isModalOpen: false }); },
                navigateTo(id, db) { const data = db[id]; if (!data) return; this.history.push({ id, db }); this.render(data); },
                back() { this.history.pop(); const prev = this.history[this.history.length - 1]; if (prev) this.render(prev.db[prev.id]); },
                render(data) {
                    this.dom.title.textContent = data.title || '';
                    this.dom.image.style.display = data.image ? 'block' : 'none';
                    if (data.image) { this.dom.image.src = data.image; this.dom.image.alt = data.alt || data.title; }
                    let backBtn = this.history.length > 1 ? `<button class="modal-back-btn">&larr; Back</button>` : '';
